async def run(args, state):
    import uuid
    order_number = str(args.get("order_number", "")).strip()
    issue_category = str(args.get("issue_category", "")).strip()
    resolution_summary = str(args.get("resolution_summary", "")).strip()
    if not order_number:
        return {"ok": False, "error": "order_number_required", "message": "Номер заказа обязателен."}
    if not issue_category:
        return {"ok": False, "error": "issue_category_required", "message": "Категория обращения обязательна."}
    if not resolution_summary:
        return {"ok": False, "error": "resolution_summary_required", "message": "Краткое резюме решения обязательно."}
    ref = f"DEMO-SUP-{uuid.uuid4().hex[:10].upper()}"
    return {
        "ok": True,
        "demo": True,
        "case_ref": ref,
        "order_number": order_number,
        "issue_category": issue_category,
    }
